const content = $json.choices?.[0]?.message?.content || '{}';
let ocr;
try {
  const match = content.match(/\{[\s\S]*\}/);
  ocr = JSON.parse(match ? match[0] : content);
} catch (e) {
  ocr = { ocrConfidence: 0, ocrIssues: ['parse_error'], ocrDocumentType: '', ocrExtractedName: '', ocrExtractedBusinessName: '', ocrLicenseNumber: '', ocrExpirationDate: '', ocrIssuingAuthority: '' };
}

const artistName = $('trigger_webhook_license_worker').item.json.body.artistName || '';
const extractedName = ocr.ocrExtractedName || '';

let nameMatch = 'unavailable';
if (extractedName && artistName) {
  const norm = s => s.toLowerCase().trim();
  if (norm(extractedName) === norm(artistName)) nameMatch = 'exact';
  else if (norm(artistName).includes(norm(extractedName.split(' ')[0])) || norm(extractedName).includes(norm(artistName.split(' ')[0]))) nameMatch = 'partial';
  else nameMatch = 'mismatch';
}

const conf = ocr.ocrConfidence ?? 0;
let verdict, verdictReason;
if (conf > 70 && (nameMatch === 'exact' || nameMatch === 'partial')) {
  verdict = 'verified'; verdictReason = 'High confidence + name match';
} else if (conf >= 40) {
  verdict = 'needs_review'; verdictReason = `Confidence ${conf}% — manual review required`;
} else {
  verdict = 'rejected'; verdictReason = `Low confidence (${conf}%) — document may be invalid`;
}

return [{ json: {
  documentId: $('trigger_webhook_license_worker').item.json.body.documentId,
  ocrDocumentType: ocr.ocrDocumentType || '',
  ocrExtractedName: ocr.ocrExtractedName || '',
  ocrExtractedBusinessName: ocr.ocrExtractedBusinessName || '',
  ocrLicenseNumber: ocr.ocrLicenseNumber || '',
  ocrExpirationDate: ocr.ocrExpirationDate || null,
  ocrIssuingAuthority: ocr.ocrIssuingAuthority || '',
  ocrConfidence: conf,
  ocrIssues: JSON.stringify(ocr.ocrIssues || []),
  ocrNameMatch: nameMatch,
  ocrVerdict: verdict,
  ocrVerdictReason: verdictReason,
  ocrProcessedAt: new Date().toISOString()
}}];
